// // This is a 8-bit shift register with parallel load and serial in, serial out capabilities.
// Module name: shift_reg_8bit
// Input ports:
//     clk: Clock signal.
//     rst: Reset signal (active low).
//     load: Load disable signal.
//     shift: Shift disable signal.
//     parallel_in[7:0]: 8-bit parallel input data.
//     serial_in: Serial input data.
// Output ports:
//     parallel_out[7:0]: 8-bit parallel output data.
//     serial_out: Serial output data.
module shift_reg_8bit(
    input clk,
    input rst,
    input load,
    input shift,
    input [7:0] parallel_in,
    input serial_in,
    output reg [7:0] parallel_out,
    output serial_out
);
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            parallel_out <= 8'b0;
        end else if (load) begin
            parallel_out <= parallel_in;
        end else if (shift) begin
            parallel_out <= {parallel_out[6:0], serial_in};
        end
    end

    assign serial_out = parallel_out[7];
endmodule

